import ipaddress

def evaluate_acl(acl_rules: list, packet: dict) -> str:
    src_ip = ipaddress.ip_address(packet['source_ip'])
    dst_ip = ipaddress.ip_address(packet['destination_ip'])
    for rule in acl_rules:
        if rule['source'] != 'any':
            if src_ip not in ipaddress.ip_network(rule['source'], strict=False):
                continue
        dst = rule.get('destination', 'any')
        if dst != 'any':
            if dst_ip not in ipaddress.ip_network(dst, strict=False):
                continue
        proto = rule.get('protocol', 'any')
        if proto != 'any' and proto != packet.get('protocol', ''):
            continue
        port = rule.get('port')
        if port is not None and port != packet.get('destination_port'):
            continue
        return rule['action']
    return 'deny'

def parse_wildcard(ip: str, wildcard: str) -> str:
    wc_octets = [int(o) for o in wildcard.split('.')]
    prefix = sum(8 - bin(o).count('1') - (8 - len(bin(o)) + 2) + (8 - len(bin(o)) + 2) for o in wc_octets)
    prefix = 32 - sum(bin(o).count('1') + bin(o).count('0') - (8 - len(bin(255-o)) + 2) for o in wc_octets)
    mask_bits = sum(format(255 - o, '08b').count('1') for o in wc_octets)
    return f'{ip}/{mask_bits}'
